#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv1 = vec2(vUv.x-0.5,vUv.y-0.5+vshift);//*uAspect.xy;

dx = texture(sampler_main,vUv+ofs[0]) - texture(sampler_main,vUv-ofs[0]);
dy = texture(sampler_main,vUv+ofs[1]) - texture(sampler_main,vUv-ofs[1]);

//RED CHANNEL (fountain)
zz = (vec2(dx.r,dy.r)) ;
ratio = .5;
red = ratio*texture(sampler_main,vUv-.004*zz).r;
red+= (1-ratio)*texture(sampler_main,vUv).r;

//GREEN CHANNEL
uv2 = uv1 ;
noise = texture(sampler_noise_lq,vUv/4);
k1 = 128;
uv2 = vec2(uv1.x, 1.0/k1*(int(uv1.y*k1)+abs(fract(uv1.y*k1)-.5))) ;
vec2 uv3 = uv2*4;
float ky = clamp01(-.5-uv3.y);
k1 = abs(fract((1-.0*uv3.y)*uv3.x*2)-.5)*8 ;
k1 = k1 - sign (k1)*1;//Verdoppelung

int n = 1 ;
float delta = .1+rand_preset*.05;
while (n <=4)
{ k1 -= (4*n*sign(k1))*ky*ky;
  ky = clamp01(ky - delta);
  delta *= 1;
  n++;}
k1 = clamp(k1,-1.6,1.6);
green = cos(k1*2)-.1 ;
//green *= 1-.3*abs(sin(k1*12));
//wave = (exp(-16*pow(uv1.x+.8-q22,2)))*q3/2+.01;
wave = sin(q1*8-vUv.x*6)/2*q3;
wave = wave * (wave >= 0) + q30*.02;
red += wave/abs(sin(1/k1+q1/8))*green*ky;

//BLUE CHANNEL (clouds)
uv2 = vUv;
z = uTime*.06 ;
zv = uTime*.08+ .2*sin(vUv*16+uTime); //##
uv2 = uv1*2+ vec2(wind,.2*uTime);
n1 = texture3D(sampler_noisevol_hq,vec3 (uv2.x,uv2.y,zv)).b;
n2 = texture3D(sampler_noisevol_hq,vec3 (uv2.x*2,uv2.y*2,zv*2)).b;
n3 = texture3D(sampler_noisevol_hq,vec3 (uv2.x*4,uv2.y*4,zv*3)).b;
n4 = texture3D(sampler_noisevol_hq,vec3 (uv2.x*8,uv2.y*8,zv*7)).b;
noise = n1 + n2/2 + n3/4 + n4/8;
noise = pow(noise,1);
uv2 = uv1+noise*.1;
blue = cloud(uv2);

//*******************************
ret1 = vec3(red,green,blue) ;
ret = ret1*.8-.005;

//ret = 0;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv0 = vUv;
//vUv = (vUv-.5)*1+.5;
uvc = (vUv-.5)*uAspect.xy+.5;
uv_l = vUv + vec2(.005*uTime,0);

float berg1 = lum(texture(sampler_noise_mq,uv_l.x/4+.02*trel))/6-vUv.y+.8;
float berg2 = lum(texture(sampler_noise_hq,uv_l.x/6))+vUv.x-.5;
sun = .1/length(sin(uvc-sunpos)); //##Vorfaktor spielen

uv2 = fract(vUv);
fountain = 1*texture(sampler_fc_main,uv2).r +2* GetBlur2(uv2).r;
fountain=foncol(fountain.r);

w = vUv.y-berg2/4-vshift; //#hier spielen
z = .2/w;
skymask = clamp01(-.2-8*q5*w); //32*w fuer mehr Leuchten
lavmask = clamp01(-1-12*w); //lava background

rs0.x = (vUv.x-.5) * (1+abs(z))*2 ; rs0.y = z; //#hier an q29 anpassen
rs0 *= 4*(z<=0)+1;

float glow = q26/length(rs0-vec2(0.,1.5+w))/4;
rs0 *= 1+glow*glow;
rs.x = rs0*2; rs.y = rs0.y + trel*.5;

float bridge = texture(sampler_main,vUv).g*skymask;

lavamod = clamp01((texture(sampler_noise_hq,rs/16)-.5));
uv_vol = vec3(rs*2,.2*trel+0*lavamod)*(z >=0); //# faster
lava = 2*clamp01(texture3D(sampler_noisevol_hq,uv_vol)-.2);
lava = lava*lavamod/sqrt(abs(z))+glow;

ret1 = (vUv.y*(1+q23)+sun)*skycol*skymask + lavcol(lum(lava)) * (1-lavmask);
ret1 *= clamp01(1-bridge*8);

smoke = texture(sampler_main,fract((vUv-.5)*1+.5)).b;
smoke  *= smoke*q5;
ret1 *= clamp01(1-smoke*sm_dens*skymask);
smoke2 = texture(sampler_main, (vUv-.5)/2+.5).b*q30; ;

ret1 += fountain -z*clamp01(smoke+w*sm_lit)*vec3(1,.4,0.1)*skymask;

ret1 += lavcol(clamp01(bridge*z*z/16));
ret1 *= clamp01(berg1*32);
ret1 = ret1*clamp01(1-smoke2)+lavcol(smoke2)*1;
ret = 1-exp(-ret1*2); //exposure control

  fragColor = ret;
}
